import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

const customers = {
  "cust-001": {
    name: "Ava Thompson",
    tier: "Gold",
    lastOrder: "2026-05-12",
    notes: "Prefers email support and is interested in premium analytics add-ons.",
  },
  "cust-002": {
    name: "Jordan Lee",
    tier: "Silver",
    lastOrder: "2026-04-28",
    notes: "Recently upgraded from starter plan and requested onboarding assistance.",
  },
  "cust-003": {
    name: "Priya Patel",
    tier: "Platinum",
    lastOrder: "2026-05-25",
    notes: "High lifetime value customer with a focus on reliability SLAs.",
  },
} as const;

type CustomerId = keyof typeof customers;

export default async function getCustomerSummary(
  request: ZuploRequest,
  context: ZuploContext
) {
  const payload = await request.json().catch(() => ({}));
  const customerId =
    typeof payload?.customerId === "string" ? payload.customerId : "";

  if (!customerId) {
    context.log.warn("Missing customerId in request body");
    return new Response("customerId is required", { status: 400 });
  }

  const customer = customers[customerId as CustomerId];
  if (!customer) {
    return new Response(`No customer found for id ${customerId}`, {
      status: 404,
    });
  }

  const summary = `Customer ${customer.name} (${customerId}) is on the ${customer.tier} tier. Last order date: ${customer.lastOrder}. Notes: ${customer.notes}`;

  return new Response(summary, {
    status: 200,
    headers: {
      "content-type": "text/plain; charset=utf-8",
    },
  });
}

